mapper.select:
select s.*,
       c.course_name,
       u.real_name as student_name
from score_record s
         left join course_info c on s.course_id = c.id
         left join sys_user u on s.student_id = u.id


        and s.schedule_id = #{scheduleId}


        and s.student_id = #{studentId}


        and s.teacher_id = #{teacherId}


order by s.id desc

mapper.update:
update score_record
usual_score = #{usualScore}, exam_score = #{examScore}, total_score = #{totalScore}, grade_level = #{gradeLevel}, remark = #{remark},
where selection_id = #{selectionId}
